/**
 * Audit logging service — records every notification dispatched through the system.
 *
 * Subscribes to notification:requested events on the EventBus and maintains
 * an append-only audit log. Each entry captures the recipient, channel,
 * priority, subject, and timestamp of the dispatched notification.
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationRequestedEvent, NotificationPriority } from '../events/event-types.js';

export interface AuditLogEntry {
  id: string;
  recipient: string;
  channel: string;
  priority: NotificationPriority;
  subject: string;
  body: string;
  timestamp: Date;
  loggedAt: Date;
}

let nextAuditId = 1;

function generateAuditId(): string {
  return `audit-${String(nextAuditId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextAuditId = 1;
}

export class AuditService {
  private log: AuditLogEntry[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      this.record(event);
    });
  }

  private record(event: NotificationRequestedEvent): void {
    const entry: AuditLogEntry = {
      id: generateAuditId(),
      recipient: event.recipient,
      channel: event.channel,
      priority: event.priority ?? 'normal',
      subject: event.subject,
      body: event.body,
      timestamp: event.timestamp,
      loggedAt: new Date(),
    };
    this.log.push(entry);
  }

  getEntries(): AuditLogEntry[] {
    return [...this.log];
  }

  getEntriesForRecipient(recipient: string): AuditLogEntry[] {
    return this.log.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: string): AuditLogEntry[] {
    return this.log.filter((e) => e.channel === channel);
  }

  getEntriesByPriority(priority: NotificationPriority): AuditLogEntry[] {
    return this.log.filter((e) => e.priority === priority);
  }

  getEntryCount(): number {
    return this.log.length;
  }

  clear(): void {
    this.log = [];
  }
}

/**
 * Notification preferences service — per-user channel overrides.
 *
 * Allows users to specify a preferred notification channel that takes
 * precedence over the priority-based router. For example, a user may
 * prefer all notifications via SMS regardless of priority.
 *
 * When no preference is set for a user, the priority router determines
 * the channel as usual.
 */

import type { NotificationPriority } from '../events/event-types.js';

export interface UserNotificationPreferences {
  /** Override channel for all priorities, if set. */
  defaultChannel?: string;
  /** Per-priority channel overrides. Takes precedence over defaultChannel. */
  channelByPriority?: Partial<Record<NotificationPriority, string>>;
}

export class NotificationPreferencesService {
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  setPreferences(userId: string, prefs: UserNotificationPreferences): void {
    this.preferences.set(userId, prefs);
  }

  getPreferences(userId: string): UserNotificationPreferences | undefined {
    return this.preferences.get(userId);
  }

  removePreferences(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  /**
   * Resolve the channel for a given user and priority.
   * Returns undefined if no preference is set, meaning the priority router
   * should determine the channel.
   */
  resolveChannel(userId: string, priority: NotificationPriority): string | undefined {
    const prefs = this.preferences.get(userId);
    if (!prefs) return undefined;

    // Per-priority override takes precedence
    const priorityOverride = prefs.channelByPriority?.[priority];
    if (priorityOverride) return priorityOverride;

    // Fall back to default channel preference
    return prefs.defaultChannel;
  }

  clear(): void {
    this.preferences.clear();
  }
}

